import{_ as e,o as n,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const i="/images/schrift015.jpg",p="/images/schrift016.jpg",s="/images/schrift017.jpg",v=JSON.parse('{"title":"Schriftübung 8","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/schrift08.md","filePath":"lektionen/schrift08.md"}'),h={name:"lektionen/schrift08.md"};function d(o,a,c,u,l,g){return n(),t("div",null,[...a[0]||(a[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="schriftubung-8" tabindex="-1">Schriftübung 8 <a class="header-anchor" href="#schriftubung-8" aria-label="Permalink to &quot;Schriftübung 8&quot;">​</a></h1><p>Vokalzeichen für den Wortanfang, falls das Wort nicht in der Schreibung mit einem vorhergehenden Wort verbunden ist:</p><p><img src="'+i+'" alt=""></p><p><img src="'+p+'" alt=""></p><h3 id="konsonantenligaturen" tabindex="-1">Konsonantenligaturen <a class="header-anchor" href="#konsonantenligaturen" aria-label="Permalink to &quot;Konsonantenligaturen&quot;">​</a></h3><p>Wenn im Wort oder Satz zwei oder mehrere Konsonanten unmittelbar aufeinander folgen, werden sie mit Ligatur (verbundenes Zeichen) geschrieben.</p><ol><li>Wenn das erste der zu verbindenden Konsonantenzeichen mit dem senkrechten Strich rechts abschließt, verliert es diesen Strich und wird vor den zweiten Konsonanten gesetzt.</li></ol><p>Ausnahme: wenn das zweite Konsonantenzeichen न् oder ल् ist, wird dieses mit Verlust des wagrechten Strichs unter das erste Konsonantenzeichen gesetzt. Je nach Schrifttype gibt es weitere Ausnahmen, die in der folgenden aufgeführt sind. Ist in der betreffenden Schrifttype eine Ligatur nicht vorgesehen, wird ein Virāma gesetzt.</p><p>Beispiele:</p><p>In der Type, die in diesem Skript verwendet wird:</p><p>ख् kh: ख्य  khya, ख्र khra</p><p>ग् g: ग्य gya, ग्र gra, ग्र्य grya</p><p>घ् gh: घ्न ghna, घ्म ghma, घ्र ghra</p><p>च् c: च्च cca, च्छ ccha, च्छ्र cchra, च्ञ cña,  च्म cma</p><p>ज् j: ज्ज jja, ज्झ jjha, ज्ञ jña, ज्ञ्य jñya, ज्म jma, ज्र jra</p><p>ञ् ñ: ञ्च ñca, ञ्छ ñcha, ञ्ज ñja</p><p>ण् ṇ: ण्ट ṇṭa, ण्ठ ṇṭha, ण्ड ṇḍa, ण्ढ ṇḍha, ण्ण ṇṇa, ण्म ṇma</p><p>त् t: त्क tka, त्त tta, त्त्य ttya, त्त्र ttra, त्त्व ttva, त्थ ttha, त्न tna, त्प tpa, त्र tra, त्र्य trya, त्व tva, त्स tsa</p><p>थ् th: थ्य thya</p><p>ध् dh: ध्न dhna, ध्म dhma, ध्र dhra, ध्व dhva</p><p>न् n: न्त nta, न्त्य ntya, न्त्र ntra, न्द nda, न्द्र ndra, न्ध ndha, न्ध्र ndhra, न्न nna, न्य nya</p><p>प् p: प्त pta, प्न pna, प्म pma, प्र pra, प्ल pla,  प्स psa</p><p>ब् b: ब्ज bja, ब्द bda, ब्ध bdha, ब्ब bba, ब्भ bbha, ब्र bra</p><p>भ् bh: भ्न bhna, भ्य bhya, भ्र bhra</p><p>म् m: म्न mna, म्प mpa, म्ब mba, म्र mra, म्ल mla</p><p>य् y: य्य yya, य्व yva</p><p>ल् l: ल्क lka, ल्प lpa, ल्ल lla, ल्व lva</p><p>व् v: व्न vna, व्य vya, व्र vra</p><p>श् ś: श्च śca, श्च्य ścya, श्न śna, श्य śya, श्र śra, श्ल śla, श्व śva श्व्य śvya</p><p>ष् ṣ: ष्ट ṣṭa, ष्ट्य ṣṭya, ष्ट्र ṣṭra, ष्ट्र्य ṣṭrya, ष्ट्र्व ṣṭrva, ष्ठ ṣṭha, ष्ठ्य ṣṭhya, ष्ण ṣṇa, ष्ण्य ṣṇya, ष्म ṣma,</p><p>स् s: स्क ska, स्ख skha, स्त sta, स्त्य stya, स्त्र stra, स्त्व stva, स्थ stha, स्न sna, स्प spa, स्र sra</p><p>Beachten Sie die Schreibung von jña:</p><p><img src="'+s+'" alt=""></p><p>Anlautendes -a, das gemäß den Satzsandhiregeln elidiert (-as + a- » -o &#39; ) wird durch den sog. Avagraha bezeichnet:</p><p>ऽ</p><p>z.B.</p><p>देवो ऽग्निः = devo &#39;gniḥ</p><h2 id="ubung" tabindex="-1">Übung <a class="header-anchor" href="#ubung" aria-label="Permalink to &quot;Übung&quot;">​</a></h2><p>A) Schreiben Sie alle in der obigen Liste vorkommenden Ligaturen</p><p>B) Schreiben und übersetzen Sie:</p><p>1. devo viṣṇuḥ.</p><p>2. sādhuścaitanyaḥ.</p><p>3. devo &#39;gniḥ.</p><p>4. deva indraḥ.</p><p>5. devaḥ kṛṣṇaḥ.</p><p>6. vaiśyaḥ.</p><p>7. guruścandrakīrtiḥ.</p><p>8. vaiśyastulādhāraḥ.</p><p>9. īśvaro viṣṇuḥ.</p><p>10. śiva īśvaraḥ.</p><p>11. devyumā.</p><p>12. devatānnapūrṇā.</p><p>13. sādhvī gurvī.</p><p>14. devyo gurvyaḥ.</p><p>15. devo nṛtyati.</p><p>16. kavirmanyate.</p><p>17. kaviḥ smarati.</p><p>18. devā yudhyante.</p><p>C) Schreiben Sie:</p><p>agraṃ agniḥ ākāśa ūrdhvaṃ īpsitaḥ āptaṃ udayo īśo āsanno uttamaṃ</p><p>D) Lesen, transliterieren und übersetzen Sie:</p><p>शूद्रा नृत्यन्ति | साध्व्यः स्मरन्ति | देव्यो मन्यन्ते | योधाञ्जयति | गुरूञ्छृणोति | पशूल्लंभते | साधुः स्वर्गं गच्छति | साधवो गुरूञ्छृण्वन्ति | नरकांश्च स्वर्गांश्च गच्छन्ति | सृष्टिः | तन्वन्ति |</p>',63)])])}const b=e(h,[["render",d]]);export{v as __pageData,b as default};
